glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
in vec3 a_position;
in vec2 a_uv0;
in vec4 a_color;
out vec2 v_uv0;
out vec4 v_color;
void main () {
  gl_Position = cc_matViewProj * vec4(a_position, 1);
  v_uv0 = a_uv0;
  v_color = a_color;
}

glsl3.frag:
precision highp float;
in vec2 v_uv0;
in vec4 v_color;
uniform sampler2D texture;
uniform Properties {
  vec2 center1;
  vec2 size1;
  float width1;
  float height1;
  vec2 center2;
  vec2 size2;
  float width2;
  float height2;
  float round;
  float feather;
};
void main () {
  vec4 color = v_color;
  color *= texture(texture, v_uv0);
  float ratio = size1.x / size1.y;
  float minX = center1.x - (width1 / 2.0);
  float maxX = center1.x + (width1 / 2.0);
  float minY = center1.y - (height1 * ratio / 2.0);
  float maxY = center1.y + (height1 * ratio / 2.0);
  if (v_uv0.x >= minX && v_uv0.x <= maxX && v_uv0.y >= minY && v_uv0.y <= maxY) {
    if (round == 0.0) discard;
    float roundY = round * ratio;
    vec2 vertex;
    if (v_uv0.x <= minX + round) {
      if (v_uv0.y <= minY + roundY) {
        vertex = vec2(minX + round, (minY + roundY) / ratio);
      } else if (v_uv0.y >= maxY - roundY) {
        vertex = vec2(minX + round, (maxY - roundY) / ratio);
      } else {
        vertex = vec2(minX + round, v_uv0.y / ratio);
      }
    } else if (v_uv0.x >= maxX - round) {
      if (v_uv0.y <= minY + roundY){
        vertex = vec2(maxX - round, (minY + roundY) / ratio);
      } else if (v_uv0.y >= maxY - roundY) {
        vertex = vec2(maxX - round, (maxY - roundY) / ratio);
      } else {
        vertex = vec2(maxX - round, v_uv0.y / ratio);
      }
    } else if (v_uv0.y <= minY + roundY) {
      vertex = vec2(v_uv0.x, (minY + roundY) / ratio);
    } else if (v_uv0.y >= maxY - roundY) {
      vertex = vec2(v_uv0.x, (maxY - roundY) / ratio);
    } else {
      discard;
    }
    float dis = distance(vec2(v_uv0.x, v_uv0.y / ratio), vertex);
    color.a = smoothstep(round - feather, round, dis) * color.a;
  }
  ratio = size2.x / size2.y;
  minX = center2.x - (width2 / 2.0);
  maxX = center2.x + (width2 / 2.0);
  minY = center2.y - (height2 * ratio / 2.0);
  maxY = center2.y + (height2 * ratio / 2.0);
  if (v_uv0.x >= minX && v_uv0.x <= maxX && v_uv0.y >= minY && v_uv0.y <= maxY) {
    if (round == 0.0) discard;
    float roundY = round * ratio;
    vec2 vertex;
    if (v_uv0.x <= minX + round) {
      if (v_uv0.y <= minY + roundY) {
        vertex = vec2(minX + round, (minY + roundY) / ratio);
      } else if (v_uv0.y >= maxY - roundY) {
        vertex = vec2(minX + round, (maxY - roundY) / ratio);
      } else {
        vertex = vec2(minX + round, v_uv0.y / ratio);
      }
    } else if (v_uv0.x >= maxX - round) {
      if (v_uv0.y <= minY + roundY){
        vertex = vec2(maxX - round, (minY + roundY) / ratio);
      } else if (v_uv0.y >= maxY - roundY) {
        vertex = vec2(maxX - round, (maxY - roundY) / ratio);
      } else {
        vertex = vec2(maxX - round, v_uv0.y / ratio);
      }
    } else if (v_uv0.y <= minY + roundY) {
      vertex = vec2(v_uv0.x, (minY + roundY) / ratio);
    } else if (v_uv0.y >= maxY - roundY) {
      vertex = vec2(v_uv0.x, (maxY - roundY) / ratio);
    } else {
      discard;
    }
    float dis = distance(vec2(v_uv0.x, v_uv0.y / ratio), vertex);
    color.a = smoothstep(round - feather, round, dis) * color.a;
  }
  color.a *= v_color.a;
  gl_FragColor = color;
}

